def fix_all_numeric_types(df, cols_to_cast):
    """
    Convierte las variables especificadas al tipo Double.

    Parameters
    ----------
    df : pyspark.sql.DataFrame
        DataFrame de entrada.
    cols_to_cast : list
        Lista de columnas que se desean convertir a Double.
    """

    for col_name in cols_to_cast:
        df = df.withColumn(col_name, F.col(col_name).cast(DoubleType()))

    return df

